#include <iostream>
using namespace std;
int main()
{
    int a,b,c,d,e,f,total=0,sum=0;
    bool flag[1005]={false};
    cin>>a>>b>>c>>d>>e>>f;
    for(int a1=0;a1<=a;a1++)
    {
        for(int a2=0;a2<=b;a2++)
        {
            for(int a3=0;a3<=c;a3++)
            {
                for(int a4=0;a4<=d;a4++)
                {
                    for(int a5=0;a5<=e;a5++)
                    {
                        for(int a6=0;a6<=f;a6++)
                        {
                            sum=a1+2*a2+3*a3+5*a4+10*a5+20*a6;
                            flag[sum]=true;
                        }
                    }
                }
            }
        }
    }
    for(int i=1;i<=1000;i++)
    {
        if(flag[i])
        {
            total++;
        }
    }
    cout<<"Total="<<total;
    return 0;
}
